from lxml import etree

def validate_xml(uploaded_file, schema_source=None):
    """
    Validate an uploaded XML document.

    Args:
        uploaded_file: file-like object opened in binary mode.
        schema_source: path to an XSD file or a file-like object (optional).

    Returns:
        (is_valid, errors): tuple
            is_valid (bool): True if XML is well-formed and, if provided, conforms to schema.
            errors (list[str]): list of human-readable error messages.
    """
    errors = []

    # Read XML content
    try:
        uploaded_file.seek(0)
        xml_bytes = uploaded_file.read()
        xml_root = etree.fromstring(xml_bytes, etree.XMLParser(dtd_validation=False))
    except etree.XMLSyntaxError as exc:
        errors.append(str(exc))
        return False, errors

    # Optionally validate against XSD schema
    if schema_source is not None:
        try:
            if isinstance(schema_source, (str, bytes, bytearray)):
                with open(schema_source, "rb") as f:
                    schema_doc = etree.parse(f)
            else:
                schema_source.seek(0)
                schema_doc = etree.parse(schema_source)
            schema = etree.XMLSchema(schema_doc)
            if not schema.validate(xml_root):
                errors.extend([str(e) for e in schema.error_log])
                return False, errors
        except (etree.XMLSchemaError, etree.XMLSyntaxError, OSError) as exc:
            errors.append(str(exc))
            return False, errors

    return True, errors